const body = ($json && $json.body) ? $json.body : ($json || {});
const tab = body.tab || 'appmetrica';
const dateFrom = body.date_from || '';
const dateTo = body.date_to || '';
const payload = body.data || body;

function formatRuDate(iso) {
  if (!iso || typeof iso !== 'string') return iso || '';
  const parts = iso.split('-');
  if (parts.length !== 3) return iso;
  const date = new Date(Date.UTC(Number(parts[0]), Number(parts[1]) - 1, Number(parts[2])));
  const months = ['янв', 'фев', 'мар', 'апр', 'май', 'июн', 'июл', 'авг', 'сен', 'окт', 'ноя', 'дек'];
  return String(date.getUTCDate()) + ' ' + months[date.getUTCMonth()];
}

const periodName = (dateFrom && dateTo)
  ? (dateFrom === dateTo ? formatRuDate(dateFrom) : formatRuDate(dateFrom) + ' - ' + formatRuDate(dateTo))
  : 'выбранный период';

function buildAppPrompt(data) {
  const events = Array.isArray(data.events) ? data.events : [];
  const find = (name) => events.find((item) => item.event_name === name) || { unique_devices: 0, total_events: 0 };
  const active = events.length ? Math.max(...events.map((item) => Number(item.unique_devices) || 0), 0) : 0;
  const openOrder = Number(find('Открыл заявку').unique_devices) || 0;
  const phoneTap = Number(find('Нажал на телефон в заявке').unique_devices) || 0;
  const registrations = Number(find('Зарегистрировался').unique_devices) || 0;
  const conversion = openOrder > 0 ? Math.round((phoneTap / openOrder) * 100) : 0;
  const lines = events.slice(0, 12).map((item) => '- ' + item.event_name + ': ' + (item.unique_devices || 0) + ' вод., ' + (item.total_events || 0) + ' раз').join('\n');
  const title = 'Отчёт по AppMetrica за период ' + periodName;
  return [
    'Ты аналитик приложения ГРУЗАП.',
    'Первая строка ответа должна быть ровно такой: ' + title,
    'Данные:',
    '- Активных водителей: ' + active,
    '- Регистраций: ' + registrations,
    '- Просмотров заявок: ' + openOrder,
    '- Нажатий на телефон: ' + phoneTap + ' (конверсия ' + conversion + '%)',
    lines || '- Нет событий',
    'Напиши короткий отчёт для руководителя в 3 блоках: что хорошо, что беспокоит, что проверить дальше.',
    'Без технарского жаргона, максимум 150 слов.'
  ].join('\n');
}

function buildMetrikaPrompt(data) {
  const summary = data.summary || {};
  const sources = Array.isArray(data.sources) ? data.sources.slice(0, 6) : [];
  const botPages = Array.isArray(data.bot_pages) ? data.bot_pages.slice(0, 6) : [];
  const title = 'Отчёт по Яндекс Метрике за период ' + periodName;
  return [
    'Ты аналитик сайта ГРУЗАП.',
    'Первая строка ответа должна быть ровно такой: ' + title,
    'Данные:',
    '- Сессии: ' + (summary.sessions || 0),
    '- Пользователи: ' + (summary.users || 0),
    '- Bounce rate: ' + (summary.bounce_rate || 0),
    '- Средняя сессия (мин): ' + (summary.avg_session_min || 0),
    '- Telegram/startURL сессии: ' + (summary.bot_sessions || 0) + ' (' + (summary.bot_activation_percent || 0) + '%)',
    'Источники:',
    sources.map((item) => '- ' + item.name + ': ' + (item.visits || 0) + ' визитов').join('\n') || '- Нет данных',
    'Telegram страницы:',
    botPages.map((item) => '- ' + item.name + ': ' + (item.visits || 0) + ' визитов').join('\n') || '- Нет данных',
    'Напиши короткий отчёт для руководителя: что хорошо, что беспокоит, какие 1-2 сигнала надо проверить дальше.',
    'Максимум 150 слов.'
  ].join('\n');
}

