  city: (row.dimensions?.[0] || {}).name || '',
  drivers: Math.round(row.metrics?.[0] || 0),
})).filter((row) => row.city && row.city !== 'Unknown');

function parseInstallSources(raw) {
  const map = {};
  if (!raw || !Array.isArray(raw.data)) return map;
  raw.data.forEach((row) => {
    const source = row.dimensions?.[0]?.name || 'Unknown';
    const metric = row.metrics?.[0] || 0;
    const installs = Array.isArray(metric) ? metric.reduce((sum, value) => sum + (value || 0), 0) : metric;
    map[source] = (map[source] || 0) + Math.round(installs || 0);
  });
  return map;
}

function getInstallTotal(raw) {
  if (raw?.totals?.[0] != null) return Math.round(raw.totals[0]);
  return Object.values(parseInstallSources(raw)).reduce((sum, value) => sum + value, 0);
}

