  const impressions = Number(row.Impressions || 0) || 0;
  const clicks = Number(row.Clicks || 0) || 0;
  const ctr = Number(row.Ctr || 0) || 0;
  const avgCpc = Number(row.AvgCpc || row.AvgClickPrice || 0) || 0;
  const conversions = Number(row.Conversions || row.GoalReaches || 0) || 0;
  const cpa = conversions > 0 ? spend / conversions : 0;
  return {
    date: row.Date || '',
    spend,
    impressions,
    clicks,
    ctr,
    avg_cpc: avgCpc,
    conversions,
    cpa,
  };
});

const directSummary = directRows.reduce((acc, row) => {
