    botPages.map((item) => '- ' + item.name + ': ' + (item.visits || 0) + ' визитов').join('\n') || '- Нет данных',
    'Напиши короткий отчёт для руководителя: что хорошо, что беспокоит, какие 1-2 сигнала надо проверить дальше.',
    'Максимум 150 слов.'
  ].join('\n');
}

function buildDirectPrompt(data) {
  const summary = data.summary || {};
  const daily = Array.isArray(data.daily) ? data.daily.slice(0, 7) : [];
  const title = 'Отчёт по Яндекс Direct за период ' + periodName;
  return [
    'Ты маркетинговый аналитик ГРУЗАП.',
    'Первая строка ответа должна быть ровно такой: ' + title,
    'Данные:',
    '- Расход: ' + (summary.spend || 0),
    '- Показы: ' + (summary.impressions || 0),
    '- Клики: ' + (summary.clicks || 0),
    '- CTR: ' + (summary.ctr || 0),
    '- Средний CPC: ' + (summary.avg_cpc || 0),
    '- Конверсии: ' + (summary.conversions || 0),
    '- CPA: ' + (summary.cpa || 0),
    'Дневная динамика:',
    daily.map((item) => '- ' + item.date + ': расход ' + item.spend + ', клики ' + item.clicks + ', конверсии ' + item.conversions).join('\n') || '- Нет данных',
    'Напиши короткий отчёт для руководителя: что хорошо, что беспокоит и где рекламная эффективность проседает.',
    'Максимум 150 слов.'
  ].join('\n');
}

let prompt = '';
if (tab === 'metrika') prompt = buildMetrikaPrompt(payload);
else if (tab === 'direct') prompt = buildDirectPrompt(payload);
else prompt = buildAppPrompt(Array.isArray(body.data) ? { events: body.data } : payload);

return [{ json: { prompt, tab, period_name: periodName } }];

const events = $('Форматирование для Дашборда1').first().json.events || [];
const geoRaw = $('AppMetrica: География').first().json.data || [];
const geo = geoRaw.map((row) => ({
  city: (row.dimensions?.[0] || {}).name || '',
  drivers: Math.round(row.metrics?.[0] || 0),
})).filter((row) => row.city && row.city !== 'Unknown');

function parseInstallSources(raw) {
  const map = {};
  if (!raw || !Array.isArray(raw.data)) return map;
  raw.data.forEach((row) => {
    const source = row.dimensions?.[0]?.name || 'Unknown';
    const metric = row.metrics?.[0] || 0;
    const installs = Array.isArray(metric) ? metric.reduce((sum, value) => sum + (value || 0), 0) : metric;
    map[source] = (map[source] || 0) + Math.round(installs || 0);
  });
  return map;
}

function getInstallTotal(raw) {
  if (raw?.totals?.[0] != null) return Math.round(raw.totals[0]);
  return Object.values(parseInstallSources(raw)).reduce((sum, value) => sum + value, 0);
}

const appIds = $('Set Inputs + Resolve Dates').first().json.app_ids || '6272311';
const useBothApps = String(appIds).includes(',');
const installs1 = $('AppMetrica: Inst1').first().json;
const installs2 = $('AppMetrica: Inst2').first().json;
const mergedSources = { ...parseInstallSources(installs1) };
let installsTotal = getInstallTotal(installs1);
if (useBothApps) {
  const secondMap = parseInstallSources(installs2);
  Object.entries(secondMap).forEach(([key, value]) => {
    mergedSources[key] = (mergedSources[key] || 0) + value;
  });
  installsTotal += getInstallTotal(installs2);
}

const appSources = Object.entries(mergedSources)
  .map(([name, installs]) => ({ name, installs }))
  .sort((a, b) => b.installs - a.installs)
  .slice(0, 8);

function metricAt(raw, index) {
  if (!raw) return 0;
  if (Array.isArray(raw.totals) && raw.totals[index] != null) return Number(raw.totals[index]) || 0;
  if (Array.isArray(raw.data) && raw.data[0] && Array.isArray(raw.data[0].metrics)) return Number(raw.data[0].metrics[index]) || 0;
  return 0;
}

function rowsToNamedMetrics(raw) {
  return Array.isArray(raw?.data)
    ? raw.data.map((row) => ({
        name: row.dimensions?.[0]?.name || row.dimensions?.[0]?.id || 'Unknown',
        visits: Number(row.metrics?.[0]) || 0,
        users: Number(row.metrics?.[1]) || 0,
        bounce_rate: Number(row.metrics?.[2]) || 0,
      }))
    : [];
}

const metrikaSummaryRaw = $('Metrika Snapshot').first().json || {};
const metrikaSeriesRaw = $('Metrika ByTime Snapshot').first().json || {};
const metrikaSourcesRaw = $('Metrika Sources Snapshot').first().json || {};
const botTrafficRaw = $('Bot Traffic Snapshot').first().json || {};

const sessions = metricAt(metrikaSummaryRaw, 0);
const users = metricAt(metrikaSummaryRaw, 1);
const bounceRate = metricAt(metrikaSummaryRaw, 2);
const avgVisitSeconds = metricAt(metrikaSummaryRaw, 3);
const botRows = Array.isArray(botTrafficRaw.data)
  ? botTrafficRaw.data.map((row) => ({
      name: row.dimensions?.[0]?.name || 'Unknown page',
      visits: Number(row.metrics?.[0]) || 0,
      users: Number(row.metrics?.[1]) || 0,
    }))
  : [];
const botSessions = botRows.reduce((sum, row) => sum + row.visits, 0);

let series = [];
if (Array.isArray(metrikaSeriesRaw.time_intervals) && Array.isArray(metrikaSeriesRaw.data?.[0]?.metrics?.[0])) {
  const labels = metrikaSeriesRaw.time_intervals.map((interval) => Array.isArray(interval) ? String(interval[0] || '') : String(interval || ''));
  const visitsSeries = metrikaSeriesRaw.data[0].metrics[0] || [];
  const usersSeries = metrikaSeriesRaw.data[0].metrics[1] || [];
  series = labels.map((label, index) => ({
    date: label,
    label: label ? label.slice(5) : '—',
    visits: Number(visitsSeries[index]) || 0,
    users: Number(usersSeries[index]) || 0,
  }));
}

const metrikaWarnings = [];
if (bounceRate >= 65) metrikaWarnings.push('Высокий bounce rate: стоит проверить релевантность рекламных посадок.');
if (sessions > 0 && (botSessions / sessions) >= 0.2) metrikaWarnings.push('Высокая доля Telegram/startURL-переходов: проверьте качество и намерение трафика.');

const sources = rowsToNamedMetrics(metrikaSourcesRaw)
  .sort((a, b) => b.visits - a.visits)
  .slice(0, 8)
  .map(({ name, visits, users }) => ({ name, visits, users }));

function extractText(raw) {
  if (typeof raw === 'string') return raw;
  if (typeof raw?.body === 'string') return raw.body;
  if (typeof raw?.data === 'string') return raw.data;
  if (typeof raw?.responseBody === 'string') return raw.responseBody;
  return '';
}

function parseTsv(text) {
  const lines = String(text || '').split(/\r?\n/).map((line) => line.trim()).filter(Boolean);
  if (!lines.length) return [];
  const headerIndex = lines.findIndex((line) => line.includes('\t') && /Date|Impressions|Clicks/.test(line));
  if (headerIndex === -1 || headerIndex === lines.length - 1) return [];
  const headers = lines[headerIndex].split('\t');
  return lines.slice(headerIndex + 1).map((line) => {
    const values = line.split('\t');
    const row = {};
    headers.forEach((header, index) => { row[header] = values[index]; });
    return row;
  });
}

const directRows = parseTsv(extractText($('Direct Snapshot').first().json)).map((row) => {
  const spend = Number(row.Cost || row.CostCur || row.CostWithVAT || 0) || 0;
  const impressions = Number(row.Impressions || 0) || 0;
  const clicks = Number(row.Clicks || 0) || 0;
  const ctr = Number(row.Ctr || 0) || 0;
  const avgCpc = Number(row.AvgCpc || row.AvgClickPrice || 0) || 0;
  const conversions = Number(row.Conversions || row.GoalReaches || 0) || 0;
  const cpa = conversions > 0 ? spend / conversions : 0;
  return {
    date: row.Date || '',
    spend,
    impressions,
    clicks,
    ctr,
    avg_cpc: avgCpc,
    conversions,
    cpa,
  };
});

const directSummary = directRows.reduce((acc, row) => {
  acc.spend += row.spend;
  acc.impressions += row.impressions;
  acc.clicks += row.clicks;
  acc.conversions += row.conversions;
  return acc;
}, { spend: 0, impressions: 0, clicks: 0, conversions: 0 });
directSummary.ctr = directSummary.impressions > 0 ? (directSummary.clicks / directSummary.impressions) * 100 : 0;
directSummary.avg_cpc = directSummary.clicks > 0 ? directSummary.spend / directSummary.clicks : 0;
directSummary.cr = directSummary.clicks > 0 ? (directSummary.conversions / directSummary.clicks) * 100 : 0;
directSummary.cpa = directSummary.conversions > 0 ? directSummary.spend / directSummary.conversions : 0;

const directWarnings = [];
if (directSummary.ctr > 0 && directSummary.ctr < 1) directWarnings.push('CTR ниже 1%: объявлениям может не хватать кликабельности.');
if (directSummary.conversions === 0) directWarnings.push('Конверсии не найдены: проверьте цели Метрики и связку с Direct.');

return [{
  json: {
    appmetrica: {
      events,
      geo,
      hours: [],
      installs_total: installsTotal,
      sources: appSources,
    },
    metrika: {
      summary: {
        sessions,
        users,
        bounce_rate: bounceRate,
        avg_session_min: avgVisitSeconds / 60,
        bot_sessions: botSessions,
        bot_activation_percent: sessions > 0 ? (botSessions / sessions) * 100 : 0,
      },
      series,
      sources,
      bot_pages: botRows.slice(0, 8),
      warnings: metrikaWarnings,
    },
    direct: {
      summary: directSummary,
      daily: directRows,
      warnings: directWarnings,
    },
  },
}];

